export const AGENT_BY_KEY: Record<string, AgentDef> = Object.fromEntries(AGENTS.map(a => [a.key, a]))
export const AGENT_BY_CHANNEL: Record<string, AgentDef> = Object.fromEntries(AGENTS.map(a => [a.channel, a]))

export const MANAGERS = AGENTS.filter(a => a.key.startsWith("mgr-"))
export const SPECIALISTS = AGENTS.filter(a => a.manager !== null)
export const ORCHESTRATOR = AGENT_BY_KEY["orchestrator"]
export const BREIN = AGENT_BY_KEY["brein"]
